import React from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'
import camera from '../components/static/camera.png'

const SellWrapper = styled.form `
display:flex;
flex-direction:column;
align-items:flex-start;
width:55%;
margin:70px auto;
`

const Head = styled.div ``

const BodySection = styled.div `
margin:40px 0;
`

const PhotoUploadSection = styled.div ``

const Title = styled.div `
font-size:1.8rem;
font-weight:900;
`

const SectionBlockTitle = styled.div `
font-size:1.5rem;
font-weight:800;
letter-spacing:2px;
color:rgba(0,0,0,0.7);
`

const Details = styled.div `
`

const GridWrapper =  styled.div `
display:grid;
grid-template-columns: auto auto;
grid-template-rows: auto auto;
grid-gap:60px 60px;
width:100%;
margin:30px 0;
`

const Department = styled.select `
width:360px;
height:40px;
border:1px solid grey;
color:grey;
border-radius:6px;
`

const Categories = styled.select `
width:360px;
height:40px;
border:1px solid grey;
color:grey;
border-radius:6px;
`

const Designer = styled.select `
width:360px;
height:40px;
border:1px solid grey;
color:grey;
border-radius:6px;
`

const Size = styled.select `
width:360px;
height:40px;
border:1px solid grey;
color:grey;
border-radius:6px;
`
const Option = styled.option ``

const Item = styled.input `
width:360px;
height:40px;
border:1px solid grey;
color:grey;
border-radius:6px;
margin-top:30px;
box-sizing:border-box;
`
const DescriptionInput = styled.textarea `
width:100%;
height:80px;
border:1px solid grey;
color:grey;
border-radius:6px;
margin-top:30px;
box-sizing:border-box;
`

const ItemName = styled.div ``

const Color = styled.div ``

const Condition = styled.div ``

const Description = styled.div ``

const Price = styled.div ``

const Photo = styled.div ``

const PhotoWrapper = styled.label `
width:220px;
height:300px;
display:inline-block;
background-color:rgba(240,240,240, 0.7);
border-radius:8px;
border:0;
background-image:url(${camera});
background-position:center;
background-size:initial;
background-repeat:no-repeat;
margin:20px 20px;
`

const PhotoInput = styled.input `
display:none;
`

const FooterWrapper = styled.div `
display:flex;
justify-content:flex-end;
align-items:center;
width:100%;
padding:0 20px;
box-sizing:border-box;
`


const Submit = styled.input `
width:100px;
height:50px;
background-color:rgb(50, 50, 50);
color:white;
border-radius:10px;
border:0;
text-align:center;
line-height:50px;
`

const Draft = styled.div `
width:200px;
height:50px;
background-color:white;
color:#1C1C1C;
border-radius:10px;
border:1px solid #1C1C1C;
text-align:center;
line-height:50px;
margin-right:20px;
`


export default function Sell () {
	return (
		<>
			<Header />
			<Navbar />
			<SellWrapper>
				<Head>
					<Title>Add a New Listing</Title>
				</Head>
				<BodySection>
					<Details>
						<SectionBlockTitle>Details</SectionBlockTitle>
						<GridWrapper>
							<Department value='Department'>
								<Option>Please Select Your Department</Option>
								<Option>MensWear</Option>
								<Option>WomensWear</Option>
							</Department>
							<Categories>
								<Option>Please Select Your Category</Option>
								<Option>MensWear</Option>
								<Option>WomensWear</Option>
							</Categories>
							<Designer>
								<Option>Please Select Your Degigner</Option>
								<Option>Maison Margiela</Option>
								<Option>Louis Vuitton</Option>
							</Designer>
							<Size>
								<Option>Please Select the size</Option>
								<Option>S</Option>
								<Option>M</Option>
								<Option>L</Option>
							</Size>
						</GridWrapper>
					</Details>
					<GridWrapper>
						<ItemName>
							<SectionBlockTitle>Item Name</SectionBlockTitle>
							<Item></Item>
						</ItemName>
						<Color>
							<SectionBlockTitle>Color</SectionBlockTitle>
							<Item></Item>
						</Color>
						<Condition>
							<SectionBlockTitle>Condition</SectionBlockTitle>
							<Item></Item>
						</Condition>
						<Price>
							<SectionBlockTitle>Price</SectionBlockTitle>
							<Item></Item>
						</Price>
					</GridWrapper>
					<Description>
						<SectionBlockTitle>Description</SectionBlockTitle>
						<DescriptionInput></DescriptionInput>
					</Description>
				</BodySection>
				<PhotoUploadSection>
					<Photo>
						<PhotoWrapper><PhotoInput type='file' accept='image/png, image/jpg'></PhotoInput></PhotoWrapper>
						<PhotoWrapper><PhotoInput type='file' accept='image/png, image/jpg'></PhotoInput></PhotoWrapper>
						<PhotoWrapper><PhotoInput type='file' accept='image/png, image/jpg'></PhotoInput></PhotoWrapper>
						<PhotoWrapper><PhotoInput type='file' accept='image/png, image/jpg'></PhotoInput></PhotoWrapper>
						<PhotoWrapper><PhotoInput type='file' accept='image/png, image/jpg'></PhotoInput></PhotoWrapper>
						<PhotoWrapper><PhotoInput type='file' accept='image/png, image/jpg'></PhotoInput></PhotoWrapper>
					</Photo>
				</PhotoUploadSection>
				<FooterWrapper>
					<Draft defaultValue='Save as Draft'></Draft>
					<Submit value='PUBLISH'></Submit>
				</FooterWrapper>
			</SellWrapper>

		</>
	)
}
